export const checkId = 'dynamic-port';
export const name = 'Dynamic Port Configuration';
export const appliesTo = ['deployable', 'server', 'framework'];

const GOOD_PATTERNS = [
  /process\.env\.PORT\b/,
  /process\.env\['PORT'\]/,
  /process\.env\["PORT"\]/,
  /import\.meta\.env\.PORT\b/,
  /Deno\.env\.get\(['"]PORT['"]\)/,
  /Bun\.env\.PORT\b/,
  /const\s*\{\s*PORT\s*(?:=\s*\d+)?\s*\}\s*=\s*process\.env/,
  /let\s*\{\s*PORT\s*(?:=\s*\d+)?\s*\}\s*=\s*process\.env/,
  /var\s*\{\s*PORT\s*(?:=\s*\d+)?\s*\}\s*=\s*process\.env/,
  /PORT\s*=\s*process\.env\.PORT/,
  /listen\s*\(\s*(?:process\.env\.PORT|Deno\.env\.get\(['"]PORT['"]\)|Bun\.env\.PORT|import\.meta\.env\.PORT)/,
];

const BAD_PATTERNS = [
  /\.listen\s*\(\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
  /\.listen\s*\(\s*\{[^}]*port\s*:\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
  /createServer\([^)]*\)\.listen\s*\(\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
];

const SERVER_DEPS = [
  'express', 'fastify', 'koa', 'hono', 'polka', 'restify', 'connect', 'micro',
  'next', 'nuxt', 'astro', 'solid-start', 'nitropack', 'h3', 'nuxi', 'http-server', 'serve-static', 'sirv',
];

const NATIVE_PORT_FRAMEWORKS = [
  'next', 'nuxt', 'astro', 'solid-start', 'nitropack', 'h3',
];

const BUILD_TOOLS = [
  'webpack', 'rollup', 'esbuild', 'vite', 'turbo', 'turborepo', 'lerna', 'nx', 'parcel', 'vitest', 'jest', 'cypress', 'playwright',
];

const CLIENT_FRAMEWORKS = [
  'react', 'vue', '@angular/core', 'svelte', 'preact', 'solid-js', 'lit',
];

function isNotApplicable(packageJson, tree) {
  if (!packageJson) return false;

  const deps = { ...(packageJson.dependencies || {}), ...(packageJson.devDependencies || {}) };
  const scripts = packageJson.scripts || {};

  const hasServerDep = SERVER_DEPS.some(d => deps[d]);
  const hasServerScript = ['start', 'serve', 'preview', 'dev'].some(s =>
    scripts[s] && /node|next|nuxt|astro|ts-node|nodemon|pm2|serve/.test(scripts[s])
  );
  const hasDeployArtifact = tree.some(p =>
    /^(Dockerfile|fly\.toml|Procfile|vercel\.json|netlify\.toml|render\.yaml|app\.yaml|wrangler\.toml|docker-compose)/.test(p)
  );
  const hasRootServerFile = tree.some(p =>
    /^(server|app|index|main|start|listen)\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p)
  );

  if (hasServerDep || hasServerScript || hasDeployArtifact || hasRootServerFile) {
    return false;
  }

  const isBuildTool = BUILD_TOOLS.some(t => deps[t] || packageJson.name?.includes(t));
  if (isBuildTool) return true;

  if (packageJson.bin && !hasServerScript) return true;

  const hasMain = !!(packageJson.main || packageJson.module || packageJson.exports);
  const keywords = packageJson.keywords || [];
  const libKeywords = ['library', 'lib', 'plugin', 'tool', 'cli', 'utility', 'utils', 'helper', 'client', 'sdk', 'package', 'middleware', 'component', 'ui'];
  const hasLibKw = keywords.some(k => libKeywords.includes(k.toLowerCase()));
  const hasPeerDeps = !!packageJson.peerDependencies;

  if (hasMain) {
    if (CLIENT_FRAMEWORKS.some(f => deps[f])) return true;
    if (hasPeerDeps || hasLibKw) return true;
  }

  const isWorkspace = !!packageJson.workspaces || tree.some(p => /^pnpm-workspace\.yaml$/.test(p));
  const hasApps = tree.some(p => /^apps\/[^/]+/.test(p));
  const hasPackages = tree.some(p => /^packages\/[^/]+/.test(p));
  if (isWorkspace && hasPackages && !hasApps && !hasServerScript) return true;

  return false;
}

function hasLibraryStructure(packageJson, tree) {
  if (!packageJson) return false;
  const hasEntry = !!(packageJson.main || packageJson.module || packageJson.exports || packageJson.bin);
  const hasExamples = tree.some(p => /^(examples?|demos)\/[^/]+/.test(p));
  const hasPackages = tree.some(p => /^packages\/[^/]+/.test(p));
  const hasStart = !!(packageJson.scripts?.start && /node|next|nuxt|astro|serve|listen/.test(packageJson.scripts.start));
  const hasDocker = tree.some(p => /^Dockerfile/.test(p));
  const hasAppsDir = tree.some(p => /^apps\/[^/]+/.test(p));

  if (hasStart || hasDocker || hasAppsDir) return false;
  if (hasEntry && (hasExamples || hasPackages)) return true;
  if (hasPackages) return true;
  return false;
}

function selectFiles(tree, packageJson) {
  const files = [];
  const add = (p) => { if (!files.includes(p)) files.push(p); };

  const isLib = hasLibraryStructure(packageJson, tree);

  ['Dockerfile', 'Procfile', 'fly.toml', 'vercel.json', 'netlify.toml', 'render.yaml', 'app.yaml', 'wrangler.toml', 'docker-compose.yml'].forEach(f => {
    if (tree.includes(f)) add(f);
  });

  const rootNames = ['server.js', 'server.ts', 'server.mjs', 'server.cjs', 'app.js', 'app.ts', 'index.js', 'index.ts', 'main.js', 'main.ts', 'start.js', 'start.ts', 'listen.js', 'listen.ts', 'www', 'bin.js', 'cli.js'];
  rootNames.forEach(n => { if (tree.includes(n)) add(n); });

  ['src/server.js', 'src/server.ts', 'src/app.js', 'src/app.ts', 'src/index.js', 'src/index.ts', 'src/main.js', 'src/main.ts'].forEach(p => {
    if (tree.includes(p)) add(p);
  });

  tree.filter(p => /^(api|routes|controllers|handlers|backend)\/[^/]+\.(js|ts|mjs|cjs)$/.test(p)).slice(0, 2).forEach(add);

  const appDirs = new Set();
  tree.forEach(p => {
    const m = p.match(/^apps\/([^/]+)\//);
    if (m) appDirs.add(m[1]);
  });
  Array.from(appDirs).slice(0, 2).forEach(app => {
    tree.filter(p =>
      p.startsWith(`apps/${app}/`) &&
      /(server|app|index|main|start)\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p) &&
      !/(\.test\.|\.spec\.|__tests__\/|\.d\.ts$|node_modules|dist\/|build\/)/.test(p)
    ).sort((a, b) => a.split('/').length - b.split('/').length).slice(0, 2).forEach(add);
  });

  const pkgDirs = new Set();
  tree.forEach(p => {
    const m = p.match(/^packages\/([^/]+)\//);
    if (m) pkgDirs.add(m[1]);
  });
  Array.from(pkgDirs).slice(0, 3).forEach(pkg => {
    tree.filter(p =>
      p.startsWith(`packages/${pkg}/`) &&
      /(server|app|index|main|start|listen)\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p) &&
      !/(\.test\.|\.spec\.|__tests__\/|\.d\.ts$|node_modules|dist\/|build\/)/.test(p)
    ).sort((a, b) => a.split('/').length - b.split('/').length).slice(0, 2).forEach(add);
  });

  if (isLib) {
    const exDirs = new Set();
    tree.forEach(p => {
      const m = p.match(/(^|\/)examples?\/([^/]+)/);
      if (m) exDirs.add(m[0]);
    });
    Array.from(exDirs).slice(0, 3).forEach(dir => {
      const prefix = dir.endsWith('/') ? dir : dir + '/';
      tree.filter(p =>
        p.startsWith(prefix) &&
        /(server|app|index|main|start)\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p) &&
        !/(\.test\.|\.spec\.|__tests__\/|\.d\.ts$|node_modules|dist\/|build\/)/.test(p)
      ).sort((a, b) => a.split('/').length - b.split('/').length).slice(0, 1).forEach(add);
    });
  }

  if (files.length < 3) {
    const topDirs = new Set();
    tree.forEach(p => {
      const parts = p.split('/');
      if (parts.length >= 2 && !/^(node_modules|\.git|dist|build|coverage|docs|test|\.github|packages|apps|examples|demos)$/.test(parts[0])) {
        topDirs.add(parts[0]);
      }
    });
    Array.from(topDirs).slice(0, 4).forEach(dir => {
      ['index.js', 'index.ts', 'server.js', 'server.ts', 'app.js', 'app.ts'].forEach(f => {
        const path = `${dir}/${f}`;
        if (tree.includes(path)) add(path);
      });
    });
  }

  if (files.length === 0) {
    tree.filter(p =>
      /(listen|server|port)\.(js|ts|mjs|cjs)$/.test(p) &&
      !/(\.test\.|\.spec\.|__tests__\/|\.d\.ts$|node_modules|dist\/|build\/)/.test(p)
    ).slice(0, 3).forEach(add);
  }

  return files.slice(0, 10);
}

function scanScripts(pkg) {
  const findings = [];
  if (!pkg?.scripts) return findings;
  for (const [name, script] of Object.entries(pkg.scripts)) {
    if (!script) continue;
    if (/process\.env\.PORT|\$PORT/.test(script)) {
      findings.push({ file: 'package.json', issue: `Script "${name}" references dynamic PORT` });
    }
    if (/\b(PORT|port)\s*[=:]\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/.test(script)) {
      findings.push({ file: 'package.json', issue: `Script "${name}" hardcodes port` });
    }
  }
  return findings;
}

export async function check(context) {
  const { tree, files, packageJson } = context;

  try {
    if (isNotApplicable(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'No server component detected — port check not applicable', findings: [] };
    }

    const allDeps = { ...(packageJson?.dependencies || {}), ...(packageJson?.devDependencies || {}) };

    const appPkgPaths = tree.filter(p => /^apps\/[^/]+\/package\.json$/.test(p)).slice(0, 3);
    const topPkgPaths = tree.filter(p =>
      /^[^/]+\/package\.json$/.test(p) &&
      !/^(node_modules|packages|apps|\.github|docs|test)\//.test(p)
    ).slice(0, 3);

    const subPkgPaths = [...new Set([...appPkgPaths, ...topPkgPaths])].slice(0, 4);

    for (const p of subPkgPaths) {
      try {
        const content = await files.get(p);
        if (content) {
          const json = JSON.parse(content);
          Object.assign(allDeps, json.dependencies, json.devDependencies);
        }
      } catch (e) {
        // ignore parse/read errors
      }
    }

    const isLib = hasLibraryStructure(packageJson, tree);
    const filesToScan = selectFiles(tree, packageJson);
    const findings = [];

    for (const filePath of filesToScan) {
      try {
        const content = await files.get(filePath);
        if (!content) continue;

        if (!isLib && (/(^|\/)examples?\//.test(filePath) || /(^|\/)demos?\//.test(filePath))) continue;
        if (/(^|\/)test\//.test(filePath) || /(^|\/)__tests__\//.test(filePath) || /(\.test\.|\.spec\.)/.test(filePath)) continue;

        if (filePath === 'Dockerfile') {
          if (/EXPOSE\s+\$PORT/.test(content)) {
            findings.push({ file: filePath, issue: 'Exposes dynamic PORT' });
          }
          if (/EXPOSE\s+(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/.test(content)) {
            findings.push({ file: filePath, issue: 'Exposes hardcoded port' });
          }
          continue;
        }

        const lines = content.split('\n');
        for (let i = 0; i < lines.length; i++) {
          const line = lines[i];
          const trimmed = line.trimStart();
          if (trimmed.startsWith('//') || trimmed.startsWith('*') || trimmed.startsWith('/*')) continue;

          for (const pat of GOOD_PATTERNS) {
            if (pat.test(line)) {
              findings.push({ file: filePath, line: i + 1, issue: 'Dynamic port configuration (process.env.PORT or equivalent)' });
              break;
            }
          }

          for (const pat of BAD_PATTERNS) {
            if (pat.test(line)) {
              const m = line.match(pat);
              const port = m ? (m[1] || m[2] || 'hardcoded') : 'hardcoded';
              findings.push({ file: filePath, line: i + 1, issue: `Hardcoded port (${port})` });
              break;
            }
          }
        }
      } catch (err) {
        console.error(`Error reading ${filePath}:`, err);
      }
    }

    findings.push(...scanScripts(packageJson));

    for (const p of subPkgPaths) {
      try {
        const content = await files.get(p);
        if (content) {
          const json = JSON.parse(content);
          const subFindings = scanScripts(json);
          subFindings.forEach(f => { f.file = `${f.file} (${p})`; });
          findings.push(...subFindings);
        }
      } catch (e) {
        // ignore
      }
    }

    const hasDynamic = findings.some(f => f.issue.includes('Dynamic port') || f.issue.includes('dynamic PORT'));
    const hasHardcoded = findings.some(f => f.issue.includes('Hardcoded port') || f.issue.includes('hardcoded port'));

    if (hasDynamic && !hasHardcoded) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Dynamic port configuration found (process.env.PORT)', findings };
    }
    if (hasHardcoded && !hasDynamic) {
      return { checkId, status: 'fail', confidence: 'high', message: 'Hardcoded port detected — should use process.env.PORT', findings };
    }
    if (hasDynamic && hasHardcoded) {
      return { checkId, status: 'check-it', confidence: 'medium', message: 'Both dynamic and hardcoded port patterns found', findings };
    }

    const hasNativePortFw = NATIVE_PORT_FRAMEWORKS.some(f => allDeps[f]);
    if (hasNativePortFw) {
      return { checkId, status: 'pass', confidence: 'medium', message: 'Framework supports dynamic port via PORT environment variable', findings: [] };
    }

    const hasServerDep = SERVER_DEPS.some(d => allDeps[d]);
    if (hasServerDep && filesToScan.length > 0) {
      return { checkId, status: 'check-it', confidence: 'low', message: 'Server dependencies found but no port patterns detected in scanned files', findings: [] };
    }

    return { checkId, status: 'not-applicable', confidence: 'medium', message: 'No server port configuration detected', findings: [] };

  } catch (err) {
    console.error('dynamic-port check error:', err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Analysis error: ${err.message}`, findings: [] };
  }
}
